#!/usr/bin/env python3
"""
Network Connectivity Probe Tool
Tests connectivity to external endpoints using DNS or HTTP methods.
Supports configurable timeout and retry parameters.
"""

import socket
import requests
import time
import sys
from typing import Optional, Dict, Any

class NetworkProbe:
    def __init__(self, method: str = "dns", host: str = "8.8.8.8", port: int = 53,
                 timeout: float = 5.0, retries: int = 3):
        self.method = method.lower()
        self.host = host
        self.port = port
        self.timeout = timeout
        self.retries = retries

        if self.method not in ["dns", "http"]:
            raise ValueError("Method must be 'dns' or 'http'")

    def probe_dns(self) -> Dict[str, Any]:
        """Perform DNS resolution probe."""
        result = {"success": False, "duration": None, "error": None}
        start_time = time.time()

        for attempt in range(self.retries):
            try:
                socket.setdefaulttimeout(self.timeout)
                resolved = socket.gethostbyname(self.host)
                duration = time.time() - start_time
                result.update({
                    "success": True,
                    "duration": round(duration, 3),
                    "resolved_ip": resolved,
                    "attempts": attempt + 1
                })
                break
            except socket.gaierror as e:
                result["error"] = f"DNS resolution failed: {e}"
                if attempt == self.retries - 1:
                    duration = time.time() - start_time
                    result["duration"] = round(duration, 3)
            except Exception as e:
                result["error"] = f"Unexpected error: {e}"
                break

        return result

    def probe_http(self) -> Dict[str, Any]:
        """Perform HTTP request probe."""
        result = {"success": False, "duration": None, "status_code": None, "error": None}
        url = f"http://{self.host}" if self.port == 80 else f"http://{self.host}:{self.port}"

        for attempt in range(self.retries):
            try:
                start_time = time.time()
                response = requests.get(url, timeout=self.timeout)
                duration = time.time() - start_time

                result.update({
                    "success": True,
                    "duration": round(duration, 3),
                    "status_code": response.status_code,
                    "attempts": attempt + 1
                })
                break
            except requests.exceptions.RequestException as e:
                result["error"] = f"HTTP request failed: {e}"
                if attempt == self.retries - 1:
                    duration = time.time() - start_time
                    result["duration"] = round(duration, 3)
            except Exception as e:
                result["error"] = f"Unexpected error: {e}"
                break

        return result

    def run(self) -> Dict[str, Any]:
        """Execute the network probe based on configured method."""
        print(f"Probing {self.host} using {self.method.upper()}...")
        print(f"Timeout: {self.timeout}s, Retries: {self.retries}")

        if self.method == "dns":
            return self.probe_dns()
        elif self.method == "http":
            return self.probe_http()
        else:
            return {"success": False, "error": "Invalid method"}

def main():
    # Default configuration for Google's public DNS
    probe = NetworkProbe(
        method="dns",
        host="8.8.8.8",
        timeout=5.0,
        retries=3
    )

    result = probe.run()

    print("\nResults:")
    print(f"Success: {result['success']}")
    if result.get('duration'):
        print(f"Duration: {result['duration']}s")
    if result.get('resolved_ip'):
        print(f"Resolved IP: {result['resolved_ip']}")
    if result.get('status_code'):
        print(f"Status Code: {result['status_code']}")
    if result.get('error'):
        print(f"Error: {result['error']}")

    sys.exit(0 if result['success'] else 1)

if __name__ == "__main__":
    main()

